def find_dispute(ds):
    ds = ds.upper().strip()
    for d in WTO_DISPUTES:
        if d["ds_number"].upper() == ds:
            return d
    return None

def search_logic(params):
    q = params.get("q","").lower()
    year = params.get("year","")
    years = params.get("years","")  # comma-separated
    agreement = params.get("agreement","")
    agreements = params.get("agreements","")
    sector = params.get("sector","")
    sectors = params.get("sectors","")
    complainant = params.get("complainant","")
    complainants = params.get("complainants","")
    respondent = params.get("respondent","")
    respondents = params.get("respondents","")
    third_party = params.get("third_party","")
    third_parties_ms = params.get("third_parties","")
    status = params.get("status","")
    measure_type = params.get("measure_type","")
    saudi = params.get("saudi_relevance","")
    has_ab = params.get("has_ab","")
    has_compliance = params.get("has_compliance","")
    year_from = params.get("year_from","")
    year_to = params.get("year_to","")
    logic = params.get("logic","AND").upper()
    page = int(params.get("page",1))
    per_page = int(params.get("per_page",30))
    sort_by = params.get("sort_by","year_desc")

    # Multi-value filters
    year_list = [y.strip() for y in years.split(",") if y.strip()] if years else []
    ag_list = [a.strip().upper() for a in agreements.split(",") if a.strip()] if agreements else []
    sec_list = [s.strip().lower() for s in sectors.split(",") if s.strip()] if sectors else []
    comp_list = [c.strip().lower() for c in complainants.split(",") if c.strip()] if complainants else []
    resp_list = [r.strip().lower() for r in respondents.split(",") if r.strip()] if respondents else []

    results = []
    for d in WTO_DISPUTES:
        filters = []

        # Full text search
        if q:
            txt = " ".join([
                d.get("title",""), d.get("short_title",""), d.get("subject",""),
                d.get("product",""), d.get("sector",""), d.get("summary_en",""),
                d.get("complainant",""), d.get("respondent",""),
                d.get("measure_type",""), " ".join(d.get("agreements",[])),
                " ".join(d.get("keywords",[])), d.get("ds_number","")
            ]).lower()
            filters.append(q in txt)

        # Year filters
        if year: filters.append(str(d.get("year",""))==year)
        if year_list: filters.append(str(d.get("year","")) in year_list)
        if year_from:
            try: filters.append((d.get("year") or 0) >= int(year_from))
            except: pass
        if year_to:
            try: filters.append((d.get("year") or 9999) <= int(year_to))
            except: pass

        # Agreement filters
        if agreement:
            ags = [a.split()[0].upper() for a in d.get("agreements",[])]
            filters.append(agreement.upper() in ags or any(agreement.upper() in a.upper() for a in d.get("agreements",[])))
        if ag_list:
            d_ags = [a.split()[0].upper() for a in d.get("agreements",[])]
            filters.append(any(ag in d_ags for ag in ag_list))

        # Sector
        if sector: filters.append(sector.lower() in d.get("sector","").lower())
        if sec_list: filters.append(any(s in d.get("sector","").lower() for s in sec_list))

        # Complainant — EXACT match against complainant_list
        if complainant:
            cn = complainant.lower().strip()
            filters.append(any(cn == c.lower().strip() for c in d.get("complainant_list",[])))
        if comp_list:
            filters.append(any(
                any(c == x.lower().strip() for x in d.get("complainant_list",[]))
                for c in comp_list
            ))

        # Respondent — EXACT match
        if respondent:
            filters.append(respondent.lower().strip() == d.get("respondent","").lower().strip())
        if resp_list:
            filters.append(any(r == d.get("respondent","").lower().strip() for r in resp_list))

        # Third party — EXACT match
        if third_party:
            cn_tp = third_party.lower().strip()
            filters.append(any(cn_tp == t.lower().strip() for t in d.get("third_parties",[])))
        # Multi-select third parties
        tp_list_param = params.get("third_parties","")
        if tp_list_param:
            tp_vals = [t.strip().lower() for t in tp_list_param.split(",") if t.strip()]
            filters.append(any(
                any(tv == t.lower().strip() for t in d.get("third_parties",[]))
                for tv in tp_vals
            ))

        # Status/Stage
        if status: filters.append(status.lower() in d.get("stage",d.get("status","")).lower())

        # Measure type
        if measure_type: filters.append(measure_type.lower() in d.get("measure_type","").lower())

        # Saudi
        if saudi: filters.append(d.get("saudi_relevance","") == saudi.upper())

        # Boolean filters
        if has_ab == "true": filters.append(d.get("has_ab") == True)
        if has_compliance == "true": filters.append(d.get("has_compliance") == True)

        # Apply logic
        if not filters:
            results.append(d)
        elif logic == "OR":
            if any(filters): results.append(d)
        else:  # AND
            if all(filters): results.append(d)

    # Sort
    def sort_key(x):
        if sort_by == "year_asc": return (x.get("year") or 0, x["ds_number"])
        if sort_by == "year_desc": return (-(x.get("year") or 0), x["ds_number"])
        if sort_by == "ds": return int(x["ds_number"].replace("DS","") or 0)
        if sort_by == "saudi": return {"HIGH":0,"MEDIUM":1,"LOW":2}.get(x.get("saudi_relevance","LOW"),3)
        if sort_by == "title": return x.get("title","")
        return (-(x.get("year") or 0), x["ds_number"])

    results.sort(key=sort_key)
    total = len(results)
    start = (page-1)*per_page
    return {
        "total": total, "page": page, "per_page": per_page,
        "pages": (total+per_page-1)//per_page,
        "disputes": results[start:start+per_page]
    }

def build_stats():
    s = {
        "total": len(WTO_DISPUTES),
        "by_year": {}, "by_sector": {}, "by_status": {},
        "by_agreement": {}, "by_complainant": {}, "by_respondent": {},
        "by_measure_type": {},
        "saudi": {"direct":0,"third_party":0,"high":0,"medium":0,"low":0},
        "has_ab": sum(1 for d in WTO_DISPUTES if d.get("has_ab")),
        "has_compliance": sum(1 for d in WTO_DISPUTES if d.get("has_compliance")),
        "multi_complainant": sum(1 for d in WTO_DISPUTES if d.get("multi_complainant")),
        "year_range": {"min": 9999, "max": 0},
        "latest": [],
    }
    for d in WTO_DISPUTES:
        y = d.get("year") or 0
        if y: s["by_year"][str(y)] = s["by_year"].get(str(y),0)+1
        if y < s["year_range"]["min"]: s["year_range"]["min"] = y
        if y > s["year_range"]["max"]: s["year_range"]["max"] = y

        sec = d.get("sector","Other")
        s["by_sector"][sec] = s["by_sector"].get(sec,0)+1

        st = d.get("stage",d.get("status",""))
        if st: s["by_status"][st] = s["by_status"].get(st,0)+1

        for code in d.get("agreement_codes",[]):
            s["by_agreement"][code] = s["by_agreement"].get(code,0)+1

        mt = d.get("measure_type","")
        if mt: s["by_measure_type"][mt] = s["by_measure_type"].get(mt,0)+1

        c = d.get("complainant",""); r = d.get("respondent","")
        for comp in d.get("complainant_list",[]):
            if comp: s["by_complainant"][comp] = s["by_complainant"].get(comp,0)+1
        if r: s["by_respondent"][r] = s["by_respondent"].get(r,0)+1

        if "Saudi Arabia" in c or "Saudi Arabia" in r: s["saudi"]["direct"]+=1
        if "Saudi Arabia" in str(d.get("third_parties",[])): s["saudi"]["third_party"]+=1
        rel = d.get("saudi_relevance","LOW")
        s["saudi"][rel.lower()] = s["saudi"].get(rel.lower(),0)+1

    s["latest"] = sorted(WTO_DISPUTES, key=lambda x:-(x.get("year") or 0))[:10]
    return s

def _exact_match(country_name, d):
    """Exact match against complainant_list, respondent, or third_parties."""
    cn = country_name.lower().strip()
    return any(cn == c.lower().strip() for c in d.get("complainant_list", []))

def _exact_resp(country_name, d):
    cn = country_name.lower().strip()
    return cn == d.get("respondent","").lower().strip()

def _exact_tp(country_name, d):
    cn = country_name.lower().strip()
    return any(cn == t.lower().strip() for t in d.get("third_parties", []))

def build_country_profile(country_name):
    as_complainant = [d for d in WTO_DISPUTES if _exact_match(country_name, d)]
    as_respondent  = [d for d in WTO_DISPUTES if _exact_resp(country_name, d)]
    as_third_party = [d for d in WTO_DISPUTES if _exact_tp(country_name, d)]

    # Opponents
    opponents_vs = {}
    for d in as_complainant:
        r = d.get("respondent","")
        if r: opponents_vs[r] = opponents_vs.get(r,0)+1

    opponents_against = {}
    for d in as_respondent:
        for c in d.get("complainant_list",[]):
            if c: opponents_against[c] = opponents_against.get(c,0)+1

    # Sector analysis
    sectors_c = {}
    for d in as_complainant + as_respondent:
        sec = d.get("sector","Other")
        sectors_c[sec] = sectors_c.get(sec,0)+1

    # Agreement analysis
    ags_c = {}
    for d in as_complainant + as_respondent:
        for code in d.get("agreement_codes",[]):
            ags_c[code] = ags_c.get(code,0)+1

    # Measure types
    mts = {}
    for d in as_complainant + as_respondent:
        mt = d.get("measure_type","")
        if mt: mts[mt] = mts.get(mt,0)+1

    # By year
    by_year = {}
    for d in as_complainant + as_respondent + as_third_party:
        y = str(d.get("year",""))
        if y: by_year[y] = by_year.get(y,0)+1

    return {
        "country": country_name,
        "as_complainant": {"total":len(as_complainant),"cases":as_complainant},
        "as_respondent":  {"total":len(as_respondent), "cases":as_respondent},
        "as_third_party": {"total":len(as_third_party),"cases":as_third_party},
        "total_involvement": len(as_complainant)+len(as_respondent)+len(as_third_party),
        "active_cases": len([d for d in as_complainant+as_respondent if d.get("stage","") not in ["Completed",""]]),
        "opponents_vs": dict(sorted(opponents_vs.items(),key=lambda x:-x[1])[:10]),
        "opponents_against": dict(sorted(opponents_against.items(),key=lambda x:-x[1])[:10]),
        "by_sector": dict(sorted(sectors_c.items(),key=lambda x:-x[1])),
        "by_agreement": dict(sorted(ags_c.items(),key=lambda x:-x[1])),
        "by_measure_type": dict(sorted(mts.items(),key=lambda x:-x[1])),
        "by_year": dict(sorted(by_year.items())),
        "win_rate": None,
    }

def ai_call(prompt, max_tokens=2000, system=None):
    if not ANTHROPIC_API_KEY or not ANTHROPIC_AVAILABLE:
        return None, "ANTHROPIC_API_KEY not configured — أضف المفتاح في Render → Environment Variables"
    try:
        client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
        kwargs = {"model":"claude-sonnet-4-20250514","max_tokens":max_tokens,
                  "messages":[{"role":"user","content":prompt}]}
        if system: kwargs["system"] = system
        msg = client.messages.create(**kwargs)
        return msg.content[0].text, None
    except Exception as e:
        return None, str(e)

