@app.route("/api/saudi-watch")
def saudi_watch():
    def sa_involved(d):
        """True if Saudi Arabia is involved in this case in any role."""
        comp_list = d.get("complainant_list", [])
        resp = d.get("respondent", "")
        tp   = d.get("third_parties", [])
        return (
            "Saudi Arabia" in comp_list or
            resp == "Saudi Arabia" or
            "Saudi Arabia" in tp or
            d.get("saudi_relevance") in ["HIGH", "MEDIUM"]
        )
    cases = [d for d in WTO_DISPUTES if sa_involved(d)]
    # Add role tag for display
    def get_sa_role(d):
        if "Saudi Arabia" in d.get("complainant_list", []):
            return "complainant"
        if d.get("respondent") == "Saudi Arabia":
            return "respondent"
        if "Saudi Arabia" in d.get("third_parties", []):
            return "third_party"
        return "related"
    for d in cases:
        d["_sa_role"] = get_sa_role(d)
    cases.sort(key=lambda x: (
        {"complainant":0,"respondent":1,"third_party":2,"related":3}.get(x.get("_sa_role","related"),3),
        {"HIGH":0,"MEDIUM":1,"LOW":2}.get(x.get("saudi_relevance","LOW"),3)
    ))
    return jsonify({"total":len(cases),"disputes":cases})

@app.route("/api/parties")
def get_parties():
    bad = {"","N/A","غير محدد"}
    comp_set, resp_set, tp_set = set(), set(), set()
    for d in WTO_DISPUTES:
        for c in d.get("complainant_list",[]):
            if c and c not in bad and len(c)>2: comp_set.add(c)
        r = d.get("respondent","").strip()
        if r and r not in bad and len(r)>2: resp_set.add(r)
        for tp in d.get("third_parties",[]):
            if tp and tp not in bad and len(tp)>2: tp_set.add(tp)
    # Merge with full WTO members list so dropdowns show ALL ~160 members
    all_members = set(WTO_MEMBERS)
    all_members.update(comp_set); all_members.update(resp_set); all_members.update(tp_set)
    all_members.discard(""); all_members.discard("N/A")
    return jsonify({
        "complainants":     sorted(all_members),
        "respondents":      sorted(all_members),
        "third_parties":    sorted(all_members),
        "all":              sorted(all_members),
        "with_cases_comp":  sorted(comp_set),
        "with_cases_resp":  sorted(resp_set),
        "with_cases_tp":    sorted(tp_set),
    })

