    writer.writerow(["DS Number","Title","Short Title","Year","Complainant","Respondent",
                     "Agreements","Sector","Measure Type","Stage","Saudi Relevance",
                     "Measure at Issue","Product","Panel Report","AB Report","Adoption","WTO URL"])
    for d in disputes:
        tl = d.get("timeline",{})
        writer.writerow([
            d.get("ds_number",""), d.get("title",""), d.get("short_title",""),
            d.get("year",""), d.get("complainant",""), d.get("respondent",""),
            "; ".join(d.get("agreements",[])), d.get("sector",""),
            d.get("measure_type",""), d.get("stage",""), d.get("saudi_relevance",""),
            d.get("subject","")[:200], d.get("product",""),
            tl.get("panel_report",""), tl.get("ab_report",""), tl.get("adoption",""),
            d.get("wto_url","")
        ])
    output.seek(0)
    return Response(output.getvalue(), mimetype="text/csv",
                    headers={"Content-Disposition":"attachment;filename=wto_disputes.csv"})

