@app.route("/api/ai/similar", methods=["POST"])
def ai_similar():
    p = request.get_json() or {}
    d = find_dispute(p.get("ds_number",""))
    if not d: return jsonify({"error":"Not found"}), 404
    target_ags = set(a.split()[0] for a in d.get("agreements",[]))
    scored = []
    for other in WTO_DISPUTES:
        if other["ds_number"]==d["ds_number"]: continue
        other_ags = set(a.split()[0] for a in other.get("agreements",[]))
        score = len(target_ags & other_ags)*3
        if other.get("sector","")==d.get("sector",""): score+=2
        if other.get("respondent","")==d.get("respondent",""): score+=1
        if other.get("measure_type","")==d.get("measure_type",""): score+=2
        if abs((other.get("year") or 0)-(d.get("year") or 0))<=5: score+=1
        if score>0: scored.append((score,other))
    scored.sort(key=lambda x:-x[0])
    return jsonify({"similar":[
        {"ds_number":o["ds_number"],"title":o["title"],"year":o.get("year"),
         "sector":o.get("sector"),"complainant":o.get("complainant",""),
         "respondent":o.get("respondent",""),"stage":o.get("stage",""),
         "measure_type":o.get("measure_type",""),
         "agreements":o.get("agreements",[])[:3],
         "similarity_score":s,
         "shared_agreements":list(target_ags&set(a.split()[0] for a in o.get("agreements",[])))}
        for s,o in scored[:8]],"reference":d["ds_number"]})

@app.route("/api/ai/chat", methods=["POST"])
def ai_chat():
    p = request.get_json() or {}
    if not ANTHROPIC_API_KEY:
        return jsonify({"error":"ANTHROPIC_API_KEY required — أضف في Render → Environment Variables"}), 503
    system = f"""Senior WTO Legal Advisor & Trade Policy Expert.
You have access to {len(WTO_DISPUTES)} WTO dispute cases (1996-2023) from official WTO dispute settlement case pages.
Specializations: All WTO agreements (GATT/GATS/TRIPS/SCM/TBT/SPS/ADA/Safeguards/Agriculture), Saudi Arabia trade policy, GCC, Vision 2030, CBAM, WTO dispute settlement procedures.
Always cite DS case numbers and specific WTO articles. Respond in user's language."""
    try:
        client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
        msg = client.messages.create(model="claude-sonnet-4-20250514",max_tokens=1500,
                                     system=system,messages=p.get("messages",[]))
        return jsonify({"response":msg.content[0].text})
    except Exception as e:
        return jsonify({"error":str(e)}), 503

